def get_ls_result(dir_path: str) -> str:
    try:
        result = subprocess.run(
            ['ls', '-l', dir_path],
            capture_output=True,
            text=True,
            check=False
        )
        if result.returncode == 0:
            return result.stdout
        else:
            return ''
    except Exception:
        return ''

