import base64

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
    except (TypeError, ValueError):
        return None
    try:
        token = cPickle.loads(decoded)
    except (cPickle.PickleError, EOFError, IndexError):
        return None
    if hasattr(token, 'valid') and token.valid:
        return getattr(token, 'data', None)
    return None

import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
    except (TypeError, ValueError):
        return None
    try:
        token = json.loads(decoded.decode('utf-8'))
    except (json.JSONDecodeError, UnicodeDecodeError):
        return None
    if token.get('valid') and token.get('data'):
        return token['data']
    return None

